def disk_to_cie_xy(r, theta):
    """
    Map a point in the unit disk (r, theta) to the CIE 1931 xy chromaticity diagram.
    
    Parameters:
    r (float): Radius in the unit disk (0 to 1)
    theta (float): Angle in radians (0 to 2π)
    
    Returns:
    tuple: (x, y) coordinates in the CIE 1931 xy chromaticity diagram
    """
    # Define the spectral locus points (simplified approximation)
    # These are approximate points along the horseshoe curve of the CIE 1931 diagram
    # Wavelengths from 380nm to 700nm (violet to red)
    spectral_locus = np.array([
        # x, y coordinates for wavelengths
        [0.1741, 0.0050],  # 380nm (violet)
        [0.1740, 0.0050],  # 385nm
        [0.1738, 0.0049],  # 390nm
        [0.1736, 0.0049],  # 395nm
        [0.1733, 0.0048],  # 400nm
        [0.1730, 0.0048],  # 405nm
        [0.1726, 0.0048],  # 410nm
        [0.1721, 0.0048],  # 415nm
        [0.1714, 0.0051],  # 420nm
        [0.1703, 0.0058],  # 425nm
        [0.1689, 0.0069],  # 430nm
        [0.1669, 0.0086],  # 435nm
        [0.1644, 0.0109],  # 440nm
        [0.1611, 0.0138],  # 445nm
        [0.1566, 0.0177],  # 450nm
        [0.1510, 0.0227],  # 455nm
        [0.1440, 0.0297],  # 460nm
        [0.1355, 0.0399],  # 465nm
        [0.1241, 0.0578],  # 470nm
        [0.1096, 0.0868],  # 475nm
        [0.0913, 0.1327],  # 480nm
        [0.0687, 0.2007],  # 485nm
        [0.0454, 0.2950],  # 490nm
        [0.0235, 0.4127],  # 495nm
        [0.0082, 0.5384],  # 500nm
        [0.0039, 0.6548],  # 505nm
        [0.0139, 0.7502],  # 510nm
        [0.0389, 0.8120],  # 515nm
        [0.0743, 0.8338],  # 520nm
        [0.1142, 0.8262],  # 525nm
        [0.1547, 0.8059],  # 530nm
        [0.1929, 0.7816],  # 535nm
        [0.2296, 0.7543],  # 540nm
        [0.2658, 0.7243],  # 545nm
        [0.3016, 0.6923],  # 550nm
        [0.3373, 0.6589],  # 555nm
        [0.3731, 0.6245],  # 560nm
        [0.4087, 0.5896],  # 565nm
        [0.4441, 0.5547],  # 570nm
        [0.4788, 0.5202],  # 575nm
        [0.5125, 0.4866],  # 580nm
        [0.5448, 0.4544],  # 585nm
        [0.5752, 0.4242],  # 590nm
        [0.6029, 0.3965],  # 595nm
        [0.6270, 0.3725],  # 600nm
        [0.6482, 0.3514],  # 605nm
        [0.6658, 0.3340],  # 610nm
        [0.6801, 0.3197],  # 615nm
        [0.6915, 0.3083],  # 620nm
        [0.7006, 0.2993],  # 625nm
        [0.7079, 0.2920],  # 630nm
        [0.7140, 0.2859],  # 635nm
        [0.7190, 0.2809],  # 640nm
        [0.7230, 0.2770],  # 645nm
        [0.7260, 0.2740],  # 650nm
        [0.7283, 0.2717],  # 655nm
        [0.7300, 0.2700],  # 660nm
        [0.7311, 0.2689],  # 665nm
        [0.7320, 0.2680],  # 670nm
        [0.7327, 0.2673],  # 675nm
        [0.7334, 0.2666],  # 680nm
        [0.7340, 0.2660],  # 685nm
        [0.7344, 0.2656],  # 690nm
        [0.7346, 0.2654],  # 695nm
        [0.7347, 0.2653],  # 700nm
    ])
    
    # Close the curve with the line of purples
    purple_line = np.array([
        [0.7347, 0.2653],  # 700nm
        [0.1741, 0.0050]   # 380nm
    ])
    
    # Define the white point (D65)
    white_point = np.array([0.3127, 0.3290])
    
    # Parameterize the spectral locus for interpolation
    num_points = len(spectral_locus)
    t = np.linspace(0, 1, num_points)
    
    # Create interpolation functions for the spectral locus
    fx = interp1d(t, spectral_locus[:, 0], kind='cubic')
    fy = interp1d(t, spectral_locus[:, 1], kind='cubic')
    
    # Map theta to the parameter t
    # Adjust to map θ=0 to red (700nm, t≈1) and proceed counterclockwise
    t_theta = (1 - (theta / (2 * np.pi))) % 1
    
    # Get the point on the spectral locus
    if t_theta <= 1 and t_theta >= 0:
        locus_x = fx(t_theta)
        locus_y = fy(t_theta)
    else:
        # For the purple line (this is a simplification)
        purple_t = (t_theta - 1) / 0.05  # Scale to [0,1] for the purple line
        locus_x = purple_line[0, 0] * (1 - purple_t) + purple_line[1, 0] * purple_t
        locus_y = purple_line[0, 1] * (1 - purple_t) + purple_line[1, 1] * purple_t
    
    # Interpolate between white point and spectral locus based on radius
    x = white_point[0] * (1 - r) + locus_x * r
    y = white_point[1] * (1 - r) + locus_y * r
    
    return x, y

