def generate_color_patch_from_xy(x, y):
    """
    Generate an approximate RGB color from CIE xy coordinates.
    This is a simplification and not colorimetrically accurate.
    
    Parameters:
    x, y (float): CIE xy coordinates
    
    Returns:
    tuple: RGB color tuple
    """
    # Convert xy to XYZ
    Y = 1.0  # Assume Y=1 for simplicity
    X = (Y / y) * x
    Z = (Y / y) * (1 - x - y)
    
    # XYZ to RGB conversion matrix (sRGB D65)
    # This is a simplified conversion matrix
    M = np.array([
        [3.2406, -1.5372, -0.4986],
        [-0.9689, 1.8758, 0.0415],
        [0.0557, -0.2040, 1.0570]
    ])
    
    # Convert to linear RGB
    rgb_linear = np.dot(M, np.array([X, Y, Z]))
    
    # Apply gamma correction
    rgb = np.zeros_like(rgb_linear)
    for i in range(3):
        if rgb_linear[i] <= 0.0031308:
            rgb[i] = 12.92 * rgb_linear[i]
        else:
            rgb[i] = 1.055 * (rgb_linear[i] ** (1/2.4)) - 0.055
    
    # Clip values to [0, 1]
    rgb = np.clip(rgb, 0, 1)
    
    return tuple(rgb)

def plot_interactive_disk_mapping():
    """
    Create an interactive plot showing color samples mapped from disk to CIE space
    """
    fig, (ax1, ax2) = plt.subplots(1, 2, figsize=(16, 8))
    
    # Setup the unit disk plot
    ax1.set_aspect('equal')
    ax1.set_xlim(-1.2, 1.2)
    ax1.set_ylim(-1.2, 1.2)
    ax1.add_patch(plt.Circle((0, 0), 1, fill=False, color='black'))
    ax1.axhline(y=0, color='gray', linestyle='--', alpha=0.5)
    ax1.axvline(x=0, color='gray', linestyle='--', alpha=0.5)
    ax1.set_title('Unit Disk')
    ax1.set_xlabel('x')
    ax1.set_ylabel('y')
    
    # Setup the CIE diagram plot
    ax2.set_aspect('equal')
    ax2.set_xlim(-0.1, 0.9)
    ax2.set_ylim(-0.1, 0.9)
    
    # Define the spectral locus points (same as before)
    spectral_locus = np.array([
        # Same data as before
        [0.1741, 0.0050],  # 380nm (violet)
        # ... other points would be here
        [0.7347, 0.2653],  # 700nm
    ])
    
    # Connect back to the starting point (Line of Purples)
    spectral_locus_closed = np.vstack([spectral_locus, spectral_locus[0]])
    
    # Plot the CIE diagram boundary
    ax2.plot(spectral_locus_closed[:, 0], spectral_locus_closed[:, 1], 'k-')
    
    # Define the white point (D65)
    white_point = np.array([0.3127, 0.3290])
    ax2.plot(white_point[0], white_point[1], 'ko', markersize=6)
    ax2.annotate('D65', xy=white_point + np.array([0.01, 0.01]))
    
    ax2.set_title('CIE 1931 xy Chromaticity Diagram')
    ax2.set_xlabel('x')
    ax2.set_ylabel('y')
    
    # Create a 2D grid of samples for visualization
    grid_size = 30
    r_values = np.linspace(0, 1, grid_size)
    theta_values = np.linspace(0, 2*np.pi, grid_size, endpoint=False)
    
    # Create a color visualization
    for r_idx, r in enumerate(r_values):
        for theta_idx, theta in enumerate(theta_values):
            # Disk coordinates
            x_disk = r * np.cos(theta)
            y_disk = r * np.sin(theta)
            
            # Map to CIE coordinates
            x_cie, y_cie = disk_to_cie_xy(r, theta)
            
            # Try to approximate the color (this is simplified)
            try:
                color = generate_color_patch_from_xy(x_cie, y_cie)
                
                # Draw color patches
                disk_patch = plt.Rectangle(
                    (x_disk-0.04, y_disk-0.04), 0.08, 0.08, 
                    color=color, alpha=0.7
                )
                ax1.add_patch(disk_patch)
                
                # Only plot some points in CIE space to avoid crowding
                if r_idx % 3 == 0 and theta_idx % 3 == 0:
                    cie_patch = plt.Rectangle(
                        (x_cie-0.01, y_cie-0.01), 0.02, 0.02, 
                        color=color, alpha=0.7
                    )
                    ax2.add_patch(cie_patch)
            except:
                # Skip invalid colors
                pass
    
    plt.suptitle('Color Mapping from Unit Disk to CIE 1931 xy Chromaticity Diagram', fontsize=16)
    plt.tight_layout()
    
    return fig

